import{bQ as t,aL as a,u as i,G as n}from"./chunks/framework.D06dwy5q.js";const e="/kb/assets/01-public-access-gates.DhRcNg89.png",d="/kb/assets/02-private-public-ip-boundary.BIOlhGIP.png",p="/kb/assets/03-eip-nat-gateway-mapping.DUV3-52N.png",l="/kb/assets/04-snat-dnat-directions.BwHIyy33.png",h="/kb/assets/05-port-listen-four-gates.ldGUygpR.png",r="/kb/assets/06-public-exposure-principle.BqN-NyD7.png",F=JSON.parse('{"title":"第 2 讲｜服务器上公网","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/02-服务器上公网.md","filePath":"00.互联网与架构基础/02-服务器上公网.md","lastUpdated":null}'),o={name:"00.互联网与架构基础/02-服务器上公网.md"};function c(k,s,g,A,b,u){return a(),i("div",null,[...s[0]||(s[0]=[n('<h1 id="第-2-讲-服务器上公网" tabindex="-1">第 2 讲｜服务器上公网 <a class="header-anchor" href="#第-2-讲-服务器上公网" aria-label="Permalink to &quot;第 2 讲｜服务器上公网&quot;">​</a></h1><p>本机执行 <code>curl http://127.0.0.1:8080</code> 能正常返回,但换一台机器或换一个网络环境,同一个服务就连不上——这是第一次部署服务时几乎所有人都会遇到的场景。</p><p>根本原因是:<strong>服务在机器内部跑起来,与外部用户能访问到它,中间还隔着公网 IP、入口转发、端口监听、防火墙、安全组这一组关卡</strong>。任何一层断了,外部都无法访问。本讲依次讲清楚这些关卡,以及云上和机房环境的差异。</p><p><img src="'+e+'" alt="服务从本机可访问到公网可访问，中间要经过多层关卡"></p><h2 id="一、ip-地址类型-内网与公网" tabindex="-1">一、IP 地址类型:内网与公网 <a class="header-anchor" href="#一、ip-地址类型-内网与公网" aria-label="Permalink to &quot;一、IP 地址类型:内网与公网&quot;">​</a></h2><p>服务器通常有两种 IP 地址:<strong>内网地址</strong>和<strong>公网地址</strong>。两者在网络可达范围、用途、计费方式上完全不同。</p><h3 id="内网-ip-的固定网段" tabindex="-1">内网 IP 的固定网段 <a class="header-anchor" href="#内网-ip-的固定网段" aria-label="Permalink to &quot;内网 IP 的固定网段&quot;">​</a></h3><p>由 RFC 1918 规定,以下三个网段是私有 IP,<strong>只能在局域网/机房/云 VPC 内部使用,无法在公网路由</strong>:</p><table tabindex="0"><thead><tr><th>网段</th><th>范围</th><th>可用地址数</th></tr></thead><tbody><tr><td><code>10.0.0.0/8</code></td><td><code>10.0.0.0</code> ~ <code>10.255.255.255</code></td><td>约 1677 万</td></tr><tr><td><code>172.16.0.0/12</code></td><td><code>172.16.0.0</code> ~ <code>172.31.255.255</code></td><td>约 105 万</td></tr><tr><td><code>192.168.0.0/16</code></td><td><code>192.168.0.0</code> ~ <code>192.168.255.255</code></td><td>约 6.5 万</td></tr></tbody></table><p>看到 IP 是这三个网段开头的,<strong>基本可以判定是内网地址</strong>——同一 VPC/机房内的机器互通,但外部公网无法直接访问。</p><h3 id="公网-ip" tabindex="-1">公网 IP <a class="header-anchor" href="#公网-ip" aria-label="Permalink to &quot;公网 IP&quot;">​</a></h3><p>不属于上述三个私有网段的地址,统称为公网 IP——<strong>全世界唯一,理论上从任何能上网的位置都能访问</strong>。云服务器一般同时分配两种 IP:</p><ul><li>内网 IP — 用于同 VPC 内机器之间互通(应用连数据库、应用调用内部 API),无流量费、低延迟</li><li>公网 IP — 用于接受外部用户的请求</li></ul><p><strong>生产环境的高频规范</strong>:应用服务器与数据库之间的通信必须走内网 IP,绝对不要走公网 IP。原因:</p><ul><li>延迟:内网通常 &lt; 1ms,公网几十到几百毫秒</li><li>流量费:云厂商对公网流量收费,内网免费</li><li>安全:数据库走公网就意味着暴露公网接口,极大增加被攻击的可能</li></ul><p><img src="'+d+`" alt="内网地址不能被公网直接路由，应用连数据库应走内网"></p><h3 id="云上公网-ip-的实现-eip-与-nat-映射" tabindex="-1">云上公网 IP 的实现:EIP 与 NAT 映射 <a class="header-anchor" href="#云上公网-ip-的实现-eip-与-nat-映射" aria-label="Permalink to &quot;云上公网 IP 的实现:EIP 与 NAT 映射&quot;">​</a></h3><p>云上的公网 IP 不一定真正绑定在虚拟机的网卡上。两种常见实现:</p><table tabindex="0"><thead><tr><th>实现方式</th><th>特征</th><th>典型云厂商</th></tr></thead><tbody><tr><td>EIP(Elastic IP)</td><td>公网 IP 是独立资源,可以挂载/卸载到 ECS 上</td><td>AWS EIP、阿里云 EIP</td></tr><tr><td>直接绑定</td><td>公网 IP 由云平台在出口做 NAT 映射,机器内 <code>ip addr</code> 只看到内网地址</td><td>部分国内云厂商的&quot;公网带宽&quot;模式</td></tr></tbody></table><p>第二种情况会让初学者困惑——<code>ip addr</code> 看不到公网 IP,但外部确实能通过公网 IP 访问。这是<strong>云平台在网关层做的 SNAT/DNAT 映射</strong>,对虚拟机内部透明。</p><p>验证一台云主机的公网 IP 实际工作方式:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从外网角度看</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://api.ipify.org</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 这个公网 IP 是云平台映射后的</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从机器内部看</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addr</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                          # 可能只看到内网 IP</span></span></code></pre></div><p><img src="`+p+`" alt="EIP 和公网带宽常由云网关层映射到虚拟机内网地址"></p><h2 id="二、机房环境与云上的概念对照" tabindex="-1">二、机房环境与云上的概念对照 <a class="header-anchor" href="#二、机房环境与云上的概念对照" aria-label="Permalink to &quot;二、机房环境与云上的概念对照&quot;">​</a></h2><p>机房自建与云上部署在物理层面差异很大,但在抽象上是对应的:</p><table tabindex="0"><thead><tr><th>机房组件</th><th>云上对应资源</th><th>职责</th></tr></thead><tbody><tr><td>物理服务器</td><td>ECS / CVM / 虚拟机实例</td><td>计算资源</td></tr><tr><td>公网出口线路</td><td>EIP / 弹性公网 IP</td><td>公网入口</td></tr><tr><td>防火墙策略</td><td>安全组 / 网络 ACL</td><td>包过滤</td></tr><tr><td>内网网段 / VLAN</td><td>VPC / 子网</td><td>网络隔离</td></tr><tr><td>入口负载均衡设备</td><td>SLB / ALB / CLB</td><td>流量分发</td></tr><tr><td>F5、A10 等专用硬件</td><td>LB 服务</td><td>高性能负载均衡</td></tr></tbody></table><p>理解这种对应关系的好处:<strong>机房经验可以直接迁移到云上,云上学到的设计模式也能应用到机房</strong>。任何一层的故障定位思路都是通用的。</p><h3 id="公网请求的标准路径" tabindex="-1">公网请求的标准路径 <a class="header-anchor" href="#公网请求的标准路径" aria-label="Permalink to &quot;公网请求的标准路径&quot;">​</a></h3><p>外部请求进入服务的标准链路:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>公网用户</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>公网 IP (EIP)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>安全组规则 (云防火墙)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>VPC / 子网</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>负载均衡 SLB (可选)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>ECS 虚拟机</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>主机防火墙 (iptables / firewalld)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>服务进程 (监听端口)</span></span></code></pre></div><p><strong>每一层都可能成为访问失败的卡点</strong>,排查时基本就是顺着这条链路逐层确认。</p><h2 id="三、nat-snat-与-dnat" tabindex="-1">三、NAT:SNAT 与 DNAT <a class="header-anchor" href="#三、nat-snat-与-dnat" aria-label="Permalink to &quot;三、NAT:SNAT 与 DNAT&quot;">​</a></h2><p>NAT(Network Address Translation,网络地址转换)是支撑&quot;内网与公网互通&quot;的核心机制。两种典型用法:</p><h3 id="snat-让内网机器主动访问公网" tabindex="-1">SNAT:让内网机器主动访问公网 <a class="header-anchor" href="#snat-让内网机器主动访问公网" aria-label="Permalink to &quot;SNAT:让内网机器主动访问公网&quot;">​</a></h3><p>许多内网服务器虽然没有公网 IP,但 <code>yum install</code>、<code>docker pull</code>、<code>curl https://api.github.com</code> 这些访问外网的操作都能成功——背后是 <strong>SNAT</strong>(Source NAT,源地址转换)在工作。</p><p><strong>机制</strong>:内网机器的请求出去时,被网关(或专门的 NAT 服务器)把源地址从内网 IP 替换成网关的公网 IP,这样目标服务器才能正确回包。回包到达网关后,网关查询转换表,反向把目标地址改回内网 IP,转交给真正发起请求的机器。整个过程对内网机器透明。</p><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20participant%20App%20as%20%E5%86%85%E7%BD%91%E5%BA%94%E7%94%A8%3Cbr%2F%3E10.0.1.10%0A%20%20participant%20NAT%20as%20NAT%20%E7%BD%91%E5%85%B3%3Cbr%2F%3E10.0.0.1%20%2F%20203.0.113.5%0A%20%20participant%20Ext%20as%20%E5%A4%96%E9%83%A8%E6%9C%8D%E5%8A%A1%3Cbr%2F%3Eapi.github.com%0A%0A%20%20App-%3E%3ENAT%3A%20%E6%BA%90%3A10.0.1.10%20%E2%86%92%20%E7%9B%AE%E7%9A%84%3Aapi.github.com%0A%20%20Note%20over%20NAT%3A%20%E6%94%B9%E5%86%99%E6%BA%90%E5%9C%B0%E5%9D%80%3Cbr%2F%3E10.0.1.10%20%E2%86%92%20203.0.113.5%0A%20%20NAT-%3E%3EExt%3A%20%E6%BA%90%3A203.0.113.5%20%E2%86%92%20%E7%9B%AE%E7%9A%84%3Aapi.github.com%0A%20%20Ext--%3E%3ENAT%3A%20%E5%93%8D%E5%BA%94%E7%BB%99%20203.0.113.5%0A%20%20Note%20over%20NAT%3A%20%E6%9F%A5%E8%BD%AC%E6%8D%A2%E8%A1%A8%2C%E5%8F%8D%E5%90%91%E6%94%B9%E5%86%99%3Cbr%2F%3E%E7%9B%AE%E7%9A%84%3A203.0.113.5%20%E2%86%92%2010.0.1.10%0A%20%20NAT--%3E%3EApp%3A%20%E5%93%8D%E5%BA%94%E7%BB%99%2010.0.1.10%0A"></div><h3 id="dnat-让公网用户访问内网服务" tabindex="-1">DNAT:让公网用户访问内网服务 <a class="header-anchor" href="#dnat-让公网用户访问内网服务" aria-label="Permalink to &quot;DNAT:让公网用户访问内网服务&quot;">​</a></h3><p>外部用户访问没有公网 IP 的内网服务,用的是 <strong>DNAT</strong>(Destination NAT,目的地址转换)。</p><p><strong>机制</strong>:公网 IP 的某个端口被映射到内网某台机器的端口上。例如负载均衡器拿到访问公网 80 端口的请求,转给内网 <code>10.0.1.10:8080</code>。这是端口转发(port forwarding)、负载均衡、Kubernetes Service 等机制的基础。</p><h3 id="snat-与-dnat-的记忆方法" tabindex="-1">SNAT 与 DNAT 的记忆方法 <a class="header-anchor" href="#snat-与-dnat-的记忆方法" aria-label="Permalink to &quot;SNAT 与 DNAT 的记忆方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>缩写</th><th>全称</th><th>替换什么</th><th>适用场景</th></tr></thead><tbody><tr><td>SNAT</td><td>Source NAT</td><td>源地址</td><td>&quot;内网主动访问外网&quot;</td></tr><tr><td>DNAT</td><td>Destination NAT</td><td>目的地址</td><td>&quot;外网访问内网服务&quot;</td></tr></tbody></table><p>记忆方法:<strong>S</strong> = Source,主动方向(我出去);<strong>D</strong> = Destination,被动方向(别人进来)。</p><p><img src="`+l+`" alt="SNAT 改源地址，DNAT 改目的地址"></p><h2 id="四、端口与监听" tabindex="-1">四、端口与监听 <a class="header-anchor" href="#四、端口与监听" aria-label="Permalink to &quot;四、端口与监听&quot;">​</a></h2><p>公网 IP 能 ping 通<strong>不代表服务能访问</strong>——还需要端口这一层正确配置。从外部请求到达应用进程,需要四个位置都对得上:</p><h3 id="_1-应用进程-必须监听在正确的地址和端口上" tabindex="-1">1. 应用进程:必须监听在正确的地址和端口上 <a class="header-anchor" href="#_1-应用进程-必须监听在正确的地址和端口上" aria-label="Permalink to &quot;1. 应用进程:必须监听在正确的地址和端口上&quot;">​</a></h3><p>最常见的坑:<strong>服务监听了 <code>127.0.0.1:8080</code> 而非 <code>0.0.0.0:8080</code></strong>。</p><p><code>127.0.0.1</code> 与 <code>0.0.0.0</code> 的区别:</p><table tabindex="0"><thead><tr><th>监听地址</th><th>含义</th><th>谁能访问</th></tr></thead><tbody><tr><td><code>127.0.0.1:8080</code></td><td>仅本机回环</td><td>仅本机</td></tr><tr><td><code>0.0.0.0:8080</code></td><td>所有网卡</td><td>所有能访问该机器的 IP</td></tr><tr><td><code>192.168.1.10:8080</code></td><td>特定网卡 IP</td><td>仅能访问该 IP 的客户端</td></tr></tbody></table><p>排查方式:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8080</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">netstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -tlnp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8080</span></span></code></pre></div><p>如果输出显示 <code>127.0.0.1:8080</code>,即使防火墙完全打开,外部仍然无法访问——必须修改服务配置,把监听地址改为 <code>0.0.0.0:8080</code> 或具体的网卡 IP。</p><h3 id="_2-主机防火墙" tabindex="-1">2. 主机防火墙 <a class="header-anchor" href="#_2-主机防火墙" aria-label="Permalink to &quot;2. 主机防火墙&quot;">​</a></h3><p>Linux 上的防火墙工具:</p><ul><li><code>iptables</code>(传统,主流)</li><li><code>firewalld</code>(RHEL 系)</li><li><code>ufw</code>(Ubuntu 简化前端)</li><li><code>nftables</code>(新一代,替代 iptables)</li></ul><p>任意一个工具阻拦了对应端口,外部都进不来。</p><h3 id="_3-云安全组" tabindex="-1">3. 云安全组 <a class="header-anchor" href="#_3-云安全组" aria-label="Permalink to &quot;3. 云安全组&quot;">​</a></h3><p><strong>云环境特有的一层</strong>——在云平台控制台配置的网络规则,作用于云内网络出入口,<strong>优先于主机内部的防火墙</strong>。</p><p>云安全组没放行的端口,<strong>流量在云平台层面就被丢弃,根本到不了虚拟机</strong>。这种情况下:</p><ul><li>机器内的服务监听正常</li><li>主机防火墙开放</li><li>但外部访问仍然超时</li></ul><p>诊断方法是<strong>用云控制台 VNC 登录机器从机器内部反向访问</strong>——如果机器内能访问、外部不能,基本就是安全组问题。</p><h3 id="_4-入口转发" tabindex="-1">4. 入口转发 <a class="header-anchor" href="#_4-入口转发" aria-label="Permalink to &quot;4. 入口转发&quot;">​</a></h3><p>如果架构里有 Nginx、负载均衡器,要确认它们的转发配置指向正确的后端地址和端口。例如:</p><ul><li>Nginx <code>proxy_pass http://10.0.1.10:8080;</code> — 后端地址写错会 502</li><li>负载均衡的 backend 配置 — 健康检查端口和路径必须可访问</li></ul><p><img src="`+h+`" alt="从外部请求到应用进程，安全组、防火墙、监听地址和转发端口都要对齐"></p><h2 id="五、按用户侧现象快速定位" tabindex="-1">五、按用户侧现象快速定位 <a class="header-anchor" href="#五、按用户侧现象快速定位" aria-label="Permalink to &quot;五、按用户侧现象快速定位&quot;">​</a></h2><p>把所有层串起来,根据用户看到的具体错误,可以快速定位故障层:</p><table tabindex="0"><thead><tr><th>用户侧现象</th><th>大概率卡在哪</th><th>排查重点</th></tr></thead><tbody><tr><td>域名报 <code>NXDOMAIN</code></td><td>DNS</td><td>域名解析记录、本地 DNS 缓存</td></tr><tr><td>浏览器一直转,最后超时</td><td>公网入口或网络层</td><td>公网 IP 可达性、安全组、防火墙、路由</td></tr><tr><td>立即返回 <code>ERR_CONNECTION_REFUSED</code></td><td>端口或服务</td><td>服务进程是否启动、是否监听对外地址</td></tr><tr><td>能连上但返回 404</td><td>路由</td><td>Nginx 路由配置、后端路由表</td></tr><tr><td>返回 502</td><td>入口到后端</td><td>Nginx error log、后端实例健康状态</td></tr><tr><td>接口慢或返回 504</td><td>后端处理</td><td>后端应用日志、数据库慢查询</td></tr></tbody></table><h3 id="实际排查的标准命令组合" tabindex="-1">实际排查的标准命令组合 <a class="header-anchor" href="#实际排查的标准命令组合" aria-label="Permalink to &quot;实际排查的标准命令组合&quot;">​</a></h3><p>新部署服务无法外部访问,从外到内依次诊断:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. 从外部访问点(本地电脑或另一台云主机)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://公网IP:80</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 看连接是否建立、是哪种错</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -zv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 公网IP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 80</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                       # 单独测端口连通性</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. 从云内部访问(如同 VPC 的另一台机器)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://内网IP:80</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 排除外网链路问题</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. 在目标机器本机访问</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:80</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 排除服务本身问题</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. 看服务监听情况</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;:80&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # 是 0.0.0.0 还是 127.0.0.1?</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 5. 看主机防火墙</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iptables</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INPUT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 计数器看包是否被丢</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">firewall-cmd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --list-all</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # firewalld 规则</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 6. 看云控制台</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 安全组规则、网络 ACL、EIP 绑定状态</span></span></code></pre></div><p>按这个顺序排查,<strong>前一步通了再继续向内</strong>:外部不通就先查安全组、内网通就排除外网链路、本机通就查防火墙、本机也不通就查服务本身。一步一步收敛范围,比&quot;凭直觉判断在哪一层&quot;高效得多。</p><h2 id="六、生产环境的端口暴露原则" tabindex="-1">六、生产环境的端口暴露原则 <a class="header-anchor" href="#六、生产环境的端口暴露原则" aria-label="Permalink to &quot;六、生产环境的端口暴露原则&quot;">​</a></h2><p>新机器投入使用前,<strong>对监听的端口做一次审查</strong>——所有不需要暴露的端口都收紧。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看本机所有监听</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntup</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 应该只暴露业务需要的端口,例如:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># - 22 (SSH,且只允许跳板机 IP)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># - 80/443 (业务)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># - 服务自身的端口(必要时仅监听内网)</span></span></code></pre></div><p>常见错误示例:</p><table tabindex="0"><thead><tr><th>服务</th><th>错误做法</th><th>正确做法</th></tr></thead><tbody><tr><td>Redis</td><td>监听 <code>0.0.0.0:6379</code> 无密码暴露公网</td><td>监听内网 IP、设密码、安全组只放行应用 IP</td></tr><tr><td>MySQL</td><td>监听 <code>0.0.0.0:3306</code> 直接对公网开放</td><td>仅内网监听,运维通过堡垒机访问</td></tr><tr><td>应用调试端口</td><td>测试用的 <code>/debug</code> 接口公网可访问</td><td>生产环境禁用或限制访问来源</td></tr><tr><td>Docker daemon</td><td><code>2375/tcp</code> 暴露</td><td>仅本地 socket、TLS 加密 + 客户端证书</td></tr></tbody></table><p>公网无认证的 Redis、Elasticsearch、MongoDB、Docker daemon 是最常见的被入侵入口——这类服务被扫描器持续扫描,默认配置就能直接连进去。<strong>任何&quot;无认证的服务&quot;都必须严格限制访问来源</strong>,绝不能裸暴露到公网。</p><p><img src="`+r+'" alt="生产环境只开放必要端口，无认证服务不要裸暴露公网"></p>',80)])])}const C=t(o,[["render",c]]);export{F as __pageData,C as default};
